1	import { useEffect, useRef } from "react";
2	import { useQuery, useMutation, useQueryClient, type QueryClient } from "@tanstack/react-query";
3	import * as api from "@/lib/api/client";
4	import type {
5	  ProbabilityEditPayload,
6	  EventTradePayload,
7	  CommentPayload,
8	  Session,
9	  MarketDetailResponse,
10	  MarketPriceMessage,
11	  MarketStatus,
12	  MarketListFilterInput,
13	} from "@/lib/api/types";
14	
15	export const queryKeys = {
16	  markets: (filters?: MarketListFilterInput) => ["markets", api.normalizeMarketListFilters(filters)] as const,
17	  market: (id: string) => ["markets", id] as const,
18	  marketEvents: (id: string) => ["markets", id, "events"] as const,
19	  marketComments: (id: string) => ["markets", id, "comments"] as const,
20	  engineStats: (id: string) => ["markets", id, "engine-stats"] as const,
21	  marketAnalytics: (id: string, interval?: string) => ["markets", id, "analytics", interval ?? "1h"] as const,
22	  accountRisk: (id: string) => ["accounts", id, "risk"] as const,
23	  accountExposure: (id: string) => ["accounts", id, "exposure"] as const,
24	  marketPnl: (marketId: string, accountId: string) => ["markets", marketId, "accounts", accountId, "pnl"] as const,
25	  accountPnl: (accountId: string) => ["accounts", accountId, "pnl"] as const,
26	  health: () => ["health"] as const,
27	  serviceIndex: () => ["service-index"] as const,
28	};
29	
30	const INITIAL_RECONNECT_DELAY_MS = 500;
31	const MAX_RECONNECT_DELAY_MS = 5000;
32	
33	function invalidateMarketCollectionQueries(qc: QueryClient) {
34	  return qc.invalidateQueries({
35	    predicate: ({ queryKey }) => Array.isArray(queryKey)
36	      && queryKey[0] === "markets"
37	      && typeof queryKey[1] === "object"
38	      && queryKey[1] !== null,
39	  });
40	}
41	
42	function invalidateMarketDependentQueries(qc: QueryClient, marketId: string) {
43	  void qc.invalidateQueries({ queryKey: queryKeys.marketEvents(marketId) });
44	  void qc.invalidateQueries({ queryKey: queryKeys.engineStats(marketId) });
45	  void invalidateMarketCollectionQueries(qc);
46	}
47	
48	function invalidateAccountExposureQuery(qc: QueryClient, accountId: string) {
49	  return qc.invalidateQueries({
50	    queryKey: queryKeys.accountExposure(accountId),
51	    exact: true,
52	  });
53	}
54	
55	function invalidateAccountExposureQueries(qc: QueryClient) {
56	  return qc.invalidateQueries({
57	    predicate: ({ queryKey }) => Array.isArray(queryKey)
58	      && queryKey.length === 3
59	      && queryKey[0] === "accounts"
60	      && typeof queryKey[1] === "string"
61	      && queryKey[2] === "exposure",
62	  });
63	}
64	
65	function refetchMarketRouteQueries(qc: QueryClient, marketId: string) {
66	  void qc.invalidateQueries({ queryKey: queryKeys.market(marketId) });
67	  invalidateMarketDependentQueries(qc, marketId);
68	}
69	
70	function isMarketStatus(value: unknown): value is MarketStatus {
71	  return value === "active" || value === "resolved" || value === "closed" || value === "draft";
72	}
73	
74	function isRecord(value: unknown): value is Record<string, unknown> {
75	  return typeof value === "object" && value !== null;
76	}
77	
78	function parseMarginals(value: unknown): Record<string, number> | null {
79	  if (!isRecord(value)) {
80	    return null;
81	  }
82	
83	  const marginals: Record<string, number> = {};
84	  for (const [outcomeId, probability] of Object.entries(value)) {
85	    if (typeof probability !== "number" || !Number.isFinite(probability)) {
86	      return null;
87	    }
88	    marginals[outcomeId] = probability;
89	  }
90	  return marginals;
91	}
92	
93	function parseMarketPriceMessage(value: unknown): MarketPriceMessage | null {
94	  if (!isRecord(value)) {
95	    return null;
96	  }
97	
98	  if (
99	    typeof value.marketId !== "string"
100	    || !isMarketStatus(value.status)
101	    || typeof value.seq !== "number"
102	    || !Number.isFinite(value.seq)
103	    || typeof value.emittedAt !== "string"
104	    || typeof value.approxFlag !== "boolean"
105	  ) {
106	    return null;
107	  }
108	
109	  const marginals = parseMarginals(value.marginals);
110	  if (!marginals) {
111	    return null;
112	  }
113	
114	  let resolutionProbabilities: Record<string, number> | undefined;
115	  if (value.resolutionProbabilities != null) {
116	    const parsedResolutionProbabilities = parseMarginals(value.resolutionProbabilities);
117	    if (!parsedResolutionProbabilities) {
118	      return null;
119	    }
120	    resolutionProbabilities = parsedResolutionProbabilities;
121	  }
122	
123	  return {
124	    marketId: value.marketId,
125	    status: value.status,
126	    marginals,
127	    seq: value.seq,
128	    emittedAt: value.emittedAt,
129	    approxFlag: value.approxFlag,
130	    resolution: typeof value.resolution === "string" ? value.resolution : undefined,
131	    resolutionProbabilities,
132	  };
133	}
134	
135	export function useMarketPriceSubscription(marketId: string, opts?: { enabled?: boolean }) {
136	  const qc = useQueryClient();
137	  const enabled = opts?.enabled ?? true;
138	  const lastSeqRef = useRef<number>(-1);
139	  const reconnectAttemptRef = useRef(0);
140	  const reconnectTimerRef = useRef<number | null>(null);
141	
142	  useEffect(() => {
143	    if (!enabled || marketId.length === 0) {
144	      lastSeqRef.current = -1;
145	      reconnectAttemptRef.current = 0;
146	      if (reconnectTimerRef.current != null) {
147	        window.clearTimeout(reconnectTimerRef.current);
148	        reconnectTimerRef.current = null;
149	      }
150	      return;
151	    }
152	
153	    lastSeqRef.current = -1;
154	    reconnectAttemptRef.current = 0;
155	
156	    let socket: WebSocket | null = null;
157	    let effectClosed = false;
158	    let terminalStatus: MarketStatus | null = null;
159	
160	    const clearReconnectTimer = () => {
161	      if (reconnectTimerRef.current != null) {
162	        window.clearTimeout(reconnectTimerRef.current);
163	        reconnectTimerRef.current = null;
164	      }
165	    };
166	
167	    const scheduleReconnect = () => {
168	      clearReconnectTimer();
169	      const attempt = reconnectAttemptRef.current;
170	      const delay = Math.min(
171	        MAX_RECONNECT_DELAY_MS,
172	        INITIAL_RECONNECT_DELAY_MS * (2 ** attempt),
173	      );
174	      reconnectAttemptRef.current += 1;
175	      reconnectTimerRef.current = window.setTimeout(() => {
176	        if (effectClosed || terminalStatus !== null) {
177	          return;
178	        }
179	        refetchMarketRouteQueries(qc, marketId);
180	        connect();
181	      }, delay);
182	    };
183	
184	    const connect = () => {
185	      if (effectClosed || terminalStatus !== null) {
186	        return;
187	      }
188	
189	      socket = new WebSocket(api.getMarketPricesWebSocketUrl(marketId));
190	
191	      socket.addEventListener("open", () => {
192	        const reconnecting = reconnectAttemptRef.current > 0;
193	        reconnectAttemptRef.current = 0;
194	        clearReconnectTimer();
195	        if (reconnecting) {
196	          refetchMarketRouteQueries(qc, marketId);
197	        }
198	      });
199	
200	      socket.addEventListener("message", (event) => {
201	        if (typeof event.data !== "string") {
202	          return;
203	        }
204	
205	        let raw: unknown;
206	        try {
207	          raw = JSON.parse(event.data);
208	        } catch {
209	          return;
210	        }
211	
212	        const update = parseMarketPriceMessage(raw);
213	        if (!update || update.marketId !== marketId || update.seq <= lastSeqRef.current) {
214	          return;
215	        }
216	
217	        lastSeqRef.current = update.seq;
218	        qc.setQueryData<MarketDetailResponse>(queryKeys.market(marketId), (current) => {
219	          if (!current) {
220	            return current;
221	          }
222	
223	          return {
224	            ...current,
225	            market: {
226	              ...current.market,
227	              status: update.status,
228	              marginals: update.marginals,
229	              resolution: update.resolution ?? current.market.resolution,
230	              resolutionProbabilities: update.resolutionProbabilities ?? current.market.resolutionProbabilities,
231	            },
232	          };
233	        });
234	
235	        invalidateMarketDependentQueries(qc, marketId);
236	
237	        if (update.status !== "active") {
238	          terminalStatus = update.status;
239	          refetchMarketRouteQueries(qc, marketId);
240	          socket?.close();
241	        }
242	      });
243	
244	      socket.addEventListener("error", () => {
245	        socket?.close();
246	      });
247	
248	      socket.addEventListener("close", () => {
249	        socket = null;
250	        if (effectClosed) {
251	          return;
252	        }
253	
254	        if (terminalStatus !== null) {
255	          return;
256	        }
257	
258	        refetchMarketRouteQueries(qc, marketId);
259	        scheduleReconnect();
260	      });
261	    };
262	
263	    connect();
